import React from 'react';
// Importamos solo lo esencial
import styles from './HeroSection.module.css'; 

function HeroSection() {
    // CRÍTICO: La única clase de diseño de Tailwind para redondeo es 'rounded-b-2xl'
    // La imagen de fondo se ha eliminado.
    return (
        <div 
          className={`${styles.hero} container-fluid rounded-b-2xl`} 
          // Mínima altura para ver claramente el redondeo
          style={{ minHeight: '150px' }}
        > 
            {/* Contenido de prueba */}
            <div className="text-center p-5 text-white">
                <p>HERO TEST (SOLO REDONDEO)</p>
            </div>
        </div>
    );
};

export default HeroSection;
